import { useEffect, useState } from "react";
import { Link } from "react-router-dom";

function Dashboard() {
  // ✅ Store questions from backend
  const [questions, setQuestions] = useState([]);

  // ✅ Fetch questions when page loads
  useEffect(() => {
    fetch("http://localhost:5000/api/questions")
      .then((res) => res.json())
      .then((data) => {
        setQuestions(data);
      })
      .catch((err) => console.error(err));
  }, []);

  return (
    <div className="dashboard-full">

      {/* Header */}
      <div className="dashboard-header">
        <h2>Dashboard</h2>
        <p>Questions posted by juniors</p>
      </div>

      {/* Questions */}
      {questions.length === 0 ? (
        <p>No questions yet</p>
      ) : (
        questions.map((q) => (
          <div key={q._id} className="dashboard-question">
            <h4>{q.title}</h4>
            <p>{q.description}</p>

            <div className="dashboard-footer">
              <span className="dashboard-tag">
                Asked by User
              </span>

              <Link to="/answers" className="dashboard-btn">
                View Answer
              </Link>
            </div>
          </div>
        ))
      )}

      {/* Ask button */}
      <Link to="/ask" className="dashboard-ask">
        Ask New Question
      </Link>

    </div>
  );
}

export default Dashboard;
